use fastly::http::{header, Method, StatusCode};
use fastly::{Error, Request, Response};

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    let method = req.get_method();

    if method == Method::GET && path == "/" {
        return Ok(Response::from_status(StatusCode::OK)
            .with_body_text_plain("Fastly Compute@Edge Router Service"));
    }

    let backend_name = match route_request(&req) {
        Some(name) => name,
        None => {
            return Ok(Response::from_status(StatusCode::NOT_FOUND)
                .with_body_text_plain("No matching backend found"));
        }
    };

    match backend_name {
        "api_backend" => {
            configure_api_backend();
            req.set_header(header::HOST, "api.example.com");
        }
        "static_backend" => {
            configure_static_backend();
            req.set_header(header::HOST, "static.example.com");
        }
        "secure_backend" => {
            configure_secure_backend();
            req.set_header(header::HOST, "secure.example.com");
        }
        _ => {
            return Ok(Response::from_status(StatusCode::INTERNAL_SERVER_ERROR)
                .with_body_text_plain("Invalid backend configuration"));
        }
    }

    sanitize_request_headers(&mut req);

    match req.send(backend_name) {
        Ok(mut resp) => {
            sanitize_response_headers(&mut resp);
            Ok(resp)
        }
        Err(e) => {
            eprintln!("Backend error: {}", e);
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain("Backend service unavailable"))
        }
    }
}

fn route_request(req: &Request) -> Option<&'static str> {
    let path = req.get_path();
    let host = req.get_header_str(header::HOST).unwrap_or("");

    if path.starts_with("/api/") {
        Some("api_backend")
    } else if path.starts_with("/static/") || path.ends_with(".css") || path.ends_with(".js") {
        Some("static_backend")
    } else if host.contains("secure.") || path.starts_with("/secure/") {
        Some("secure_backend")
    } else if path.starts_with("/health") {
        None
    } else {
        Some("api_backend")
    }
}

