fn sanitize_request_headers(req: &mut Request) {
    let dangerous_headers = [
        "X-Forwarded-Host",
        "X-Original-URL",
        "X-Rewrite-URL",
    ];

    for header_name in &dangerous_headers {
        req.remove_header(header_name);
    }

    if req.get_header_str("X-Forwarded-For").is_none() {
        if let Some(client_ip) = req.get_client_ip_addr() {
            req.set_header("X-Forwarded-For", client_ip.to_string());
        }
    }

    req.set_header("X-Forwarded-Proto", req.get_url().scheme());
}

fn sanitize_response_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains",
    );

    resp.remove_header("Server");
    resp.remove_header("X-Powered-By");
}